import express from 'express'

import { Config } from '@verdaccio/types'

// Prevent prototype pollution
// https://medium.com/@instatunnel/prototype-pollution-the-javascript-vulnerability-that-poisons-your-entire-app-%EF%B8%8F-bad082616771
const prototypePollutionProtection = (config: Config): express.RequestHandler => {
  return express.json({
    strict: false,
    limit: config.max_body_size || '10mb',
    // Explicitly reject __proto__ and constructor
    verify: (_req, _res, buf) => {
      const str = buf.toString()
      if (str.includes('__proto__') || str.includes('"constructor"') || str.includes('"prototype"')) {
        throw new Error('Invalid JSON')
      }
    },
  })
}

export default prototypePollutionProtection
