import buildDebug from 'debug'
import { Express } from 'express'

import { pluginUtils } from '@verdaccio/core'
import { Config, Logger } from '@verdaccio/types'

import {
  setSecurityHeaders,
  blockUnwantedRequests,
  redirectNpmStyleUrl,
  prototypePollutionProtection,
  profanityFilter,
  blacklistFilter,
} from './middlewares'

const debug = buildDebug('verdaccio:plugin:pro:middleware')

export interface MiddlewareConfig {
  enabled: boolean
  /** When omitted, true. Set to false to skip this middleware. */
  prototypePollutionProtection?: boolean
  profanityFilter?: boolean
  blacklistFilter?: boolean
  securityHeaders?: boolean
  blockUnwantedRequests?: boolean
  redirectNpmStyleUrl?: boolean
}

class MiddlewarePlugin
  extends pluginUtils.Plugin<MiddlewareConfig>
  implements pluginUtils.ExpressMiddleware<MiddlewareConfig, pluginUtils.Storage<MiddlewareConfig>, pluginUtils.Auth<MiddlewareConfig>> {
  public config: Config
  public logger: Logger
  private middlewareConfig: MiddlewareConfig

  public constructor(config: MiddlewareConfig, options: pluginUtils.PluginOptions) {
    super(config, options)
    this.config = options.config
    this.logger = options.logger
    this.middlewareConfig = config
  }

  public register_middlewares(
    app: Express,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    _auth: pluginUtils.Auth<MiddlewareConfig>,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    _storage: pluginUtils.Storage<MiddlewareConfig>,
  ): void {
    if (!this.middlewareConfig.enabled) {
      return
    }
    debug('Verdaccio Pro Middleware plugin is enabled')

    const c = this.middlewareConfig
    if (c.securityHeaders !== false) {
      app.use(setSecurityHeaders)
    }
    if (c.prototypePollutionProtection !== false) {
      app.use(prototypePollutionProtection(this.config))
    }
    if (c.blockUnwantedRequests !== false) {
      app.use(blockUnwantedRequests)
    }
    if (c.profanityFilter !== false) {
      app.use(profanityFilter)
    }
    if (c.blacklistFilter !== false) {
      app.use(blacklistFilter)
    }
    if (c.redirectNpmStyleUrl !== false) {
      app.use('/package/{*all}', redirectNpmStyleUrl(this.logger))
    }
  }
}

export default MiddlewarePlugin
